def area(a,b,c):
    return a[0]*(b[1]-c[1])+b[0]*(c[1]-a[1])+c[0]*(a[1]-b[1])

n = int(input())
arr = []
for i in range(n):
    x,y = map(int,input().split())
    arr.append((x,y))

res = 0
for i in range(n):
    for j in range(i+1,n):
        for k in range(j+1,n):
            if area(arr[i],arr[j],arr[k]) != 0:
                res += 1

print(res)
